import React from "react";
import { Navigate } from "react-router-dom";

/**
 * ProtectedRoute ensures only logged-in users
 * (and optionally users of a specific role)
 * can access a route.
 *
 * Usage:
 * <ProtectedRoute allowedRole="student">
 *   <StudentDashboard />
 * </ProtectedRoute>
 */

const ProtectedRoute = ({ allowedRole, children }) => {
  // Get saved user and token from localStorage
  const user = JSON.parse(localStorage.getItem("user"));
  const token = localStorage.getItem("token");

  // Not logged in → redirect to login
  if (!user || !token) {
    return <Navigate to="/login" replace />;
  }

  // Logged in but wrong role → redirect to their correct dashboard
  if (allowedRole && user.role !== allowedRole) {
    if (user.role === "student") return <Navigate to="/student/dashboard" replace />;
    if (user.role === "mentor") return <Navigate to="/mentor/dashboard" replace />;
    if (user.role === "coordinator") return <Navigate to="/coordinator/dashboard" replace />;
    return <Navigate to="/login" replace />;
  }

  // If everything checks out, show the page
  return children;
};

export default ProtectedRoute;
